(function(){
const form=document.getElementById('vh360-bible-import-form');const out=document.getElementById('vh360-bible-import-progress');const strings=(window.vh360StudioBibleAdmin&&vh360StudioBibleAdmin.strings)||{};
async function api(path,opts){opts=opts||{};opts.headers=Object.assign({'X-WP-Nonce':vh360StudioBibleAdmin.nonce},opts.headers||{});const r=await fetch(vh360StudioBibleAdmin.restRoot+path,opts);const j=await r.json();if(!r.ok)throw new Error(j.message||strings.requestFailed||'Request failed.');return j;}
function label(key,fallback){return strings[key]||fallback;}function renderJob(job){if(!out)return;out.textContent=[`${label('status','Status')}: ${job.status}`,`${label('processed','Processed')}: ${job.rows_processed}`,`${label('imported','Imported')}: ${job.rows_imported}`,`${label('omitted','Omitted')}: ${job.rows_omitted}`,`${label('failed','Failed')}: ${job.rows_failed}`,`${label('books','Books')}: ${job.book_count}`].join('\n');}
if(form){form.addEventListener('submit',async e=>{e.preventDefault();try{out.textContent=strings.uploading||'Uploading…';let job=await api('/bible/imports',{method:'POST',body:new FormData(form)});while(!['completed','failed','cancelled'].includes(job.status)){renderJob(job);job=await api('/bible/imports/'+job.id+'/batch',{method:'POST'});}renderJob(job);if(job.status==='completed')location.reload();}catch(err){out.textContent=err.message;}});}
document.addEventListener('click',async e=>{const b=e.target.closest('[data-bible-admin-action]');if(!b)return;const action=b.getAttribute('data-bible-admin-action');const key=b.getAttribute('data-key');const id=b.getAttribute('data-id');try{if(action==='enable')await api('/bible/translations/'+encodeURIComponent(key)+'/enable',{method:'POST'});if(action==='disable')await api('/bible/translations/'+encodeURIComponent(key)+'/disable',{method:'POST'});if(action==='delete'&&window.confirm(strings.confirmDelete||'Delete this translation and all of its verses?'))await api('/bible/translations/'+encodeURIComponent(key),{method:'DELETE'});if(action==='cancel-import')await api('/bible/imports/'+encodeURIComponent(id),{method:'DELETE'});if(action==='clean-import')await api('/bible/imports/'+encodeURIComponent(id)+'/clean',{method:'POST'});location.reload();}catch(err){if(out)out.textContent=err.message;}});
})();
